  Edit: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" /></svg>,
  Save: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M5 13l4 4L19 7" /></svg>,
  Delete: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>,
  Add: () => <svg width="16" height="16" fill="none" viewBox="0 0 24 24" stroke="white" strokeWidth="2"><path d="M12 4v16m8-8H4" /></svg>
};

const StaffManager = () => {
  const { user } = useAuth();
  const { staffList, addStaff, deleteStaff, updateStaffInfo } = useData();

  const [formData, setFormData] = useState({ name: '', username: '', password: '' });
  const [editMode, setEditMode] = useState(null);
  const [editForm, setEditForm] = useState({});

  // --- QUYỀN HẠN: CHỈ CHIEF MỚI DÙNG ĐƯỢC FILE NÀY ---
  const isChief = user?.role === 'chief';

  if (!isChief) return <div style={{padding:'20px', color:'red'}}>Bạn không có quyền truy cập quản lý nhân sự cấp cao.</div>;

  const handleAdd = (e) => {
    e.preventDefault();
    if (!formData.name || !formData.username || !formData.password) return;
    addStaff({ ...formData, role: 'staff', positions: [], baseUBI: 0, ubiPercentage: 100, status: 'active' });
    setFormData({ name: '', username: '', password: '' });
  };

  const startEdit = (staff) => {
    setEditMode(staff.id); // Khóa ID đang sửa
    setEditForm({ ...staff }); // Clone dữ liệu để tránh tham chiếu
  };

  const saveEdit = (id) => {
    updateStaffInfo(id, editForm);
    setEditMode(null);
    setEditForm({});
    alert("Cập nhật thành công!");
  };

  const handlePositionToggle = (pos) => {
    const current = editForm.positions || [];
    setEditForm({ 
        ...editForm, 
        positions: current.includes(pos) ? current.filter(p => p !== pos) : [...current, pos] 
    });
  };

  const roleName = (r) => (r === 'chief' ? 'Chief Admin' : r === 'reg' ? 'Regulatory Admin' : r === 'op' ? 'Operational Admin' : 'Staff');

  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #003366', paddingBottom: '10px' }}>Quản lý Tài khoản (Chief Only)</h2>

      {/* Form thêm mới */}
      <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 2px 8px rgba(0,0,0,0.05)', marginBottom: '20px' }}>
        <h4 style={{ margin: '0 0 15px 0', color: '#003366' }}>+ Tạo tài khoản mới</h4>
        <form onSubmit={handleAdd} style={{ display: 'flex', gap: '10px', flexWrap: 'wrap' }}>
          <input placeholder="Họ tên" value={formData.name} onChange={e => setFormData({ ...formData, name: e.target.value })} required style={styles.input} />
          <input placeholder="Username" value={formData.username} onChange={e => setFormData({ ...formData, username: e.target.value })} required style={styles.input} />
          <input placeholder="Password" type="password" value={formData.password} onChange={e => setFormData({ ...formData, password: e.target.value })} required style={styles.input} />
          <button type="submit" style={styles.btnAdd}><Icons.Add /> Tạo</button>
        </form>
      </div>

      {/* Danh sách */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))', gap: '20px' }}>
        {staffList.map(staff => (
          <div key={staff.id} style={{ 
              background: 'white', borderRadius: '8px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', padding: '15px', 
              border: editMode === staff.id ? '2px solid #003366' : '1px solid #e0e0e0',
              opacity: (staff.status === 'suspended' && editMode !== staff.id) ? 0.6 : 1
          }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '10px', borderBottom: '1px solid #eee', paddingBottom: '8px' }}>
               <div><strong>{staff.name}</strong><br/><small>@{staff.username}</small></div>
               <span style={{ background: '#f0f2f5', padding: '2px 8px', borderRadius: '4px', fontSize: '0.7rem', height: 'fit-content' }}>{roleName(staff.role)}</span>
            </div>

            {editMode === staff.id ? (
                <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                    <div style={styles.group}>
                        <label style={styles.label}>Quyền hệ thống</label>
                        <select value={editForm.role} onChange={e => setEditForm({...editForm, role: e.target.value})} style={styles.inputFull}>
                            <option value="staff">Staff</option>
                            <option value="op">Operational Admin</option>
                            <option value="reg">Regulatory Admin</option>
                            <option value="chief">Chief Admin</option>
                        </select>
                    </div>
                    
                    {/* Chief có quyền xét Functional Roles cho Reg/Op/Staff */}
                    <div style={styles.group}>
                        <label style={styles.label}>Vị trí chức năng</label>
                        <div style={{display:'flex', flexWrap:'wrap', gap:'5px'}}>
                            {['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => (
                                <label key={r} style={styles.checkboxLabel}>
                                    <input type="checkbox" checked={editForm.positions?.includes(r)} onChange={() => handlePositionToggle(r)}/> {r}
                                </label>
                            ))}
                        </div>
                    </div>

                    <div style={styles.group}>
                        <label style={styles.label}>UBI & Trạng thái</label>
                        <div style={{display:'flex', gap:'5px'}}>
                            <input type="number" value={editForm.baseUBI} onChange={e => setEditForm({...editForm, baseUBI: Number(e.target.value)})} placeholder="Base UBI" style={styles.inputFull}/>
                            <select value={editForm.ubiPercentage} onChange={e => setEditForm({...editForm, ubiPercentage: Number(e.target.value)})} style={{width:'80px', ...styles.inputFull}}>
                                <option value={100}>100%</option><option value={75}>75%</option><option value={50}>50%</option><option value={25}>25%</option>
                            </select>
                        </div>
                        <select value={editForm.status} onChange={e => setEditForm({...editForm, status: e.target.value})} style={{marginTop:'5px', ...styles.inputFull}}>
                            <option value="active">Active</option><option value="suspended">Suspended</option>
                        </select>
                    </div>

                    <div style={{display:'flex', gap:'5px'}}>
                        <button onClick={() => saveEdit(staff.id)} style={styles.btnSave}><Icons.Save/> Lưu</button>
                        <button onClick={() => setEditMode(null)} style={styles.btnCancel}>Hủy</button>
                    </div>
                </div>
            ) : (
                <div style={{ fontSize: '0.85rem' }}>
                    {staff.status === 'suspended' && <div style={{color:'red', fontWeight:'bold'}}>⚠ Bị đình chỉ</div>}
                    <div style={{marginTop:'10px', paddingTop:'10px', borderTop:'1px dashed #eee', display:'flex', justifyContent:'flex-end', gap:'5px'}}>
                        <button onClick={() => startEdit(staff)} style={styles.btnEdit}><Icons.Edit/> Điều chỉnh</button>
                        <button onClick={() => { if(window.confirm('Xóa?')) deleteStaff(staff.id) }} style={styles.btnDelete}><Icons.Delete/> Xóa</button>
                    </div>
                </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

const styles = {
    input: { padding: '8px', border: '1px solid #ddd', borderRadius: '4px', flex: 1 },
    inputFull: { padding: '6px', border: '1px solid #ddd', borderRadius: '4px', width: '100%', boxSizing: 'border-box' },
    group: { background: '#f9f9f9', padding: '8px', borderRadius: '4px' },
    label: { fontSize: '0.7rem', fontWeight: 'bold', color: '#666', marginBottom: '3px', display: 'block' },
    checkboxLabel: { fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '3px', background: 'white', padding: '2px 5px', border: '1px solid #eee', borderRadius: '3px' },
    btnAdd: { background: '#28a745', color: 'white', border: 'none', borderRadius: '4px', padding: '8px 15px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' },
    btnSave: { background: '#003366', color: 'white', border: 'none', borderRadius: '4px', padding: '6px', flex: 1, cursor: 'pointer', display: 'flex', justifyContent: 'center', alignItems: 'center', gap: '5px' },
    btnCancel: { background: '#888', color: 'white', border: 'none', borderRadius: '4px', padding: '6px 12px', cursor: 'pointer' },
    btnEdit: { background: 'white', border: '1px solid #003366', color: '#003366', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' },
    btnDelete: { background: '#ffebee', border: '1px solid #ffcdd2', color: '#d32f2f', borderRadius: '4px', padding: '5px 10px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '5px' }
};

export default StaffManager;
